UPDATE pm_facilitator_form_d365 pd LEFT JOIN pm_facilitator pf ON (pf.`account` IS NULL AND pf.`name` = pd.`name`) OR pf.`account` = pd.`account` LEFT JOIN `pm_subcontract_facilitator` psf ON (psf.`account` IS NULL AND psf.`name` = pd.`name` ) OR psf.`account` = pd.`account` SET pf.account = pd.`account` , pf.name = pd.`name` , pf.bankAccount = pd.`bankAccount` , pf.bankInfo = pd.`bankInfo` , pf.cnapsCode = pd.`cnapsCode` , pf.contacts = IFNULL(pf.`contacts`, pd.contacts) , pf.tel = IFNULL(pf.tel, pd.`tel`) , pf.email = IFNULL(pf.email, pd.email) , pf.state = pd.`state` , pf.relateType = pd.relateType , pf.effectiveFrom = IFNULL(pf.`effectiveFrom`, pd.`effectiveFrom`) , pf.effectiveTo = IFNULL(pf.`effectiveTo`, pd.`effectiveTo`) , pf.customInfo = JSON_MERGE_PATCH(IFNULL(pf.customInfo, "{}"), IFNULL(pd.customInfo, '{}'))
, psf.account = pd.`account` , psf.name = pd.`name` , psf.bankAccount = pd.`bankAccount` , psf.bankInfo = pd.`bankInfo` , psf.cnapsCode = pd.`cnapsCode` , psf.contacts = IFNULL(psf.`contacts`, pd.contacts) , psf.tel = IFNULL(psf.tel, pd.`tel`) , psf.email = IFNULL(psf.email, pd.email) , psf.state = pd.`state` , psf.relateType = pd.relateType , psf.effectiveFrom = IFNULL(psf.`effectiveFrom`, pd.`effectiveFrom`) , psf.effectiveTo = IFNULL(psf.`effectiveTo`, pd.`effectiveTo`) , psf.customInfo = JSON_MERGE_PATCH(IFNULL(psf.customInfo, "{}"), IFNULL(pd.customInfo, '{}'))
