INSERT INTO pm_facilitator (id, `account`, `name`, `bankAccount`, `bankInfo`, `cnapsCode`, `contacts`, `tel`, `email`, `state`,`relateType`, `effectiveFrom`, `effectiveTo`, `customInfo`) SELECT pf.`id` AS id, pd.`account`, pd.`name`, pd.`bankAccount`, pd.`bankInfo`, pd.`cnapsCode`, IFNULL(pf.`contacts`, pd.contacts) AS contacts, IFNULL(pf.tel, pd.`tel`) AS tel , IFNULL(pf.email, pd.email) AS email, pd.`state`, pd.relateType , IFNULL(pf.`effectiveFrom`, pd.`effectiveFrom`) AS effectiveFrom , IFNULL(pf.`effectiveTo`, pd.`effectiveTo`) AS effectiveTo , JSON_MERGE_PATCH(IFNULL(pf.customInfo, "{}"), IFNULL(pd.customInfo, '{}')) FROM pm_facilitator_form_d365 pd LEFT JOIN pm_facilitator pf ON (pf.`account` IS NULL AND pf.`name` = pd.`name`) OR pf.`account` = pd.`account` WHERE pd.`relateType` REGEXP '安服外包' ON DUPLICATE KEY UPDATE account = VALUES(account), NAME = VALUES(NAME), bankInfo = VALUES(bankInfo), bankAccount = VALUES(bankAccount), cnapsCode = VALUES(cnapsCode), contacts = VALUES(contacts), tel = VALUES(tel), email = VALUES(email), state = VALUES(state), relateType = VALUES(relateType), effectiveFrom = VALUES(effectiveFrom), effectiveTo = VALUES(effectiveTo), customInfo = VALUES(customInfo);
INSERT INTO pm_subcontract_facilitator (id, `account`, `name`, `bankAccount`, `bankInfo`, `cnapsCode`, `contacts`, `tel`, `email`, `state`,`relateType`, `effectiveFrom`, `effectiveTo`, `customInfo`) SELECT pf.`id` AS id, pd.`account`, pd.`name`, pd.`bankAccount`, pd.`bankInfo`, pd.`cnapsCode`, IFNULL(pf.`contacts`, pd.contacts) AS contacts, IFNULL(pf.tel, pd.`tel`) AS tel , IFNULL(pf.email, pd.email) AS email, pd.`state`, pd.relateType , IFNULL(pf.`effectiveFrom`, pd.`effectiveFrom`) AS effectiveFrom , IFNULL(pf.`effectiveTo`, pd.`effectiveTo`) AS effectiveTo , JSON_MERGE_PATCH(IFNULL(pf.customInfo, "{}"), IFNULL(pd.customInfo, '{}')) FROM pm_facilitator_form_d365 pd LEFT JOIN pm_subcontract_facilitator pf ON (pf.`account` IS NULL AND pf.`name` = pd.`name`) OR pf.`account` = pd.`account` WHERE pd.`relateType` REGEXP '用服外包' ON DUPLICATE KEY UPDATE account = VALUES(account), NAME = VALUES(NAME), bankInfo = VALUES(bankInfo), bankAccount = VALUES(bankAccount), cnapsCode = VALUES(cnapsCode), contacts = VALUES(contacts), tel = VALUES(tel), email = VALUES(email), state = VALUES(state), relateType = VALUES(relateType), effectiveFrom = VALUES(effectiveFrom), effectiveTo = VALUES(effectiveTo), customInfo = VALUES(customInfo);

